    20→import Cypher from "@neo4j/cypher-builder";
    21→import type { Node } from "../classes";
    22→import type { RelationField, Context, GraphQLWhereArg } from "../types";
    23→import { aggregationFieldRegEx, AggregationFieldRegexGroups, whereRegEx } from "./where/utils";
    24→import { createBaseOperation } from "./where/property-operations/create-comparison-operation";
    25→import { NODE_OR_EDGE_KEYS, LOGICAL_OPERATORS, AGGREGATION_AGGREGATE_COUNT_OPERATORS } from "../constants";
    26→
    27→type logicalOperator = "AND" | "OR";
    28→
    29→type WhereFilter = Record<string | logicalOperator, any>;
    30→
    31→export type AggregateWhereInput = {
    32→    count: number;
    33→    count_LT: number;
    34→    count_LTE: number;
    35→    count_GT: number;
    36→    count_GTE: number;
    37→    node: WhereFilter;
    38→    edge: WhereFilter;
    39→} & WhereFilter;
    40→
    41→type AggregateWhereReturn = {
    42→    returnProjections: ("*" | Cypher.ProjectionColumn)[];
    43→    predicates: Cypher.Predicate[];
    44→};
    45→
    46→export function aggregatePreComputedWhereFields(
    47→    value: GraphQLWhereArg,
    48→    relationField: RelationField,
    49→    context: Context,
    50→    matchNode: Cypher.Variable
    51→): {
    52→    predicate: Cypher.Predicate | undefined;
    53→    preComputedSubquery: Cypher.Call;
    54→} {
    55→    const refNode = context.nodes.find((x) => x.name === relationField.typeMeta.name) as Node;
    56→    const direction = relationField.direction;
    57→    const aggregationTarget = new Cypher.Node({ labels: refNode.getLabels(context) });
    58→    const cypherRelation = new Cypher.Relationship({
    59→        source: matchNode as Cypher.Node,
    60→        target: aggregationTarget,
    61→        type: relationField.type,
    62→    });
    63→    if (direction === "IN") {
    64→        cypherRelation.reverse();
    65→    }
    66→    const matchQuery = new Cypher.Match(cypherRelation);
    67→    const { returnProjections, predicates } = aggregateWhere(
    68→        value as AggregateWhereInput,
    69→        refNode,
    70→        aggregationTarget,
    71→        cypherRelation
    72→    );
    73→    matchQuery.return(...returnProjections);
    74→    const subquery = new Cypher.Call(matchQuery).innerWith(matchNode);
    75→    return {
    76→        predicate: Cypher.and(...predicates),
    77→        preComputedSubquery: subquery,
    78→    };
    79→}
    80→
    81→export function aggregateWhere(
    82→    aggregateWhereInput: AggregateWhereInput,
    83→    refNode: Node,
    84→    aggregationTarget: Cypher.Node,
    85→    cypherRelation: Cypher.Relationship
    86→): AggregateWhereReturn {
    87→    const returnProjections: ("*" | Cypher.ProjectionColumn)[] = [];
    88→    const predicates: Cypher.Predicate[] = [];
    89→    Object.entries(aggregateWhereInput).forEach(([key, value]) => {
    90→        if (AGGREGATION_AGGREGATE_COUNT_OPERATORS.includes(key)) {
    91→            const { returnProjection: innerReturnProjection, predicate: innerPredicate } =
    92→                createCountPredicateAndProjection(aggregationTarget, key, value);
    93→            returnProjections.push(innerReturnProjection);
    94→            predicates.push(innerPredicate);
    95→        } else if (NODE_OR_EDGE_KEYS.includes(key)) {
    96→            const target = key === "edge" ? cypherRelation : aggregationTarget;
    97→            const { returnProjections: innerReturnProjections, predicates: innerPredicates } = aggregateEntityWhere(
    98→                value,
    99→                refNode,
   100→                target
   101→            );
   102→            returnProjections.push(...innerReturnProjections);
   103→            predicates.push(...innerPredicates);
   104→        } else if (LOGICAL_OPERATORS.includes(key)) {
   105→            const logicalOperator = key === "AND" ? Cypher.and : Cypher.or;
   106→            const logicalPredicates: Cypher.Predicate[] = [];
   107→            value.forEach((whereInput) => {
   108→                const { returnProjections: innerReturnProjections, predicates: innerPredicates } = aggregateWhere(
   109→                    whereInput,
   110→                    refNode,
   111→                    aggregationTarget,
   112→                    cypherRelation
   113→                );
   114→                returnProjections.push(...innerReturnProjections);
   115→                logicalPredicates.push(...innerPredicates);
   116→            });
   117→            predicates.push(logicalOperator(...logicalPredicates));
   118→        }
   119→    });
   120→    return {
   121→        returnProjections,
   122→        predicates,
   123→    };
   124→}
   125→
   126→function createCountPredicateAndProjection(
   127→    aggregationTarget: Cypher.Node,
   128→    filterKey: string,
   129→    filterValue: number
   130→): {
   131→    returnProjection: "*" | Cypher.ProjectionColumn;
   132→    predicate: Cypher.Predicate;
   133→} {
   134→    const paramName = new Cypher.Param(filterValue);
   135→    const count = Cypher.count(aggregationTarget);
   136→    const operator = whereRegEx.exec(filterKey)?.groups?.operator || "EQ";
   137→    const operation = createBaseOperation({
   138→        operator,
   139→        property: count,
   140→        param: paramName,
   141→    });
   142→    const operationVar = new Cypher.Variable();
   143→    return {
   144→        returnProjection: [operation, operationVar],
   145→        predicate: Cypher.eq(operationVar, new Cypher.Literal(true)),
   146→    };
   147→}
   148→
   149→function aggregateEntityWhere(
   150→    aggregateEntityWhereInput: WhereFilter,
   151→    refNode: Node,
   152→    target: Cypher.Node | Cypher.Relationship
   153→): AggregateWhereReturn {
   154→    const returnProjections: ("*" | Cypher.ProjectionColumn)[] = [];
   155→    const predicates: Cypher.Predicate[] = [];
   156→    Object.entries(aggregateEntityWhereInput).forEach(([key, value]) => {
   157→        if (LOGICAL_OPERATORS.includes(key)) {
   158→            const logicalOperator = key === "AND" ? Cypher.and : Cypher.or;
   159→            const logicalPredicates: Cypher.Predicate[] = [];
   160→            value.forEach((whereInput) => {
   161→                const { returnProjections: innerReturnProjections, predicates: innerPredicates } = aggregateEntityWhere(
   162→                    whereInput,
   163→                    refNode,
   164→                    target
   165→                );
   166→                returnProjections.push(...innerReturnProjections);
   167→                logicalPredicates.push(...innerPredicates);
   168→            });
   169→            predicates.push(logicalOperator(...logicalPredicates));
   170→        } else {
   171→            const operation = createEntityOperation(refNode, target, key, value);
   172→            const operationVar = new Cypher.Variable();
   173→            returnProjections.push([operation, operationVar]);
   174→            predicates.push(Cypher.eq(operationVar, new Cypher.Literal(true)));
   175→        }
   176→    });
   177→    return {
   178→        returnProjections,
   179→        predicates,
   180→    };
   181→}
   182→
   183→function createEntityOperation(
   184→    refNode: Node,
   185→    target: Cypher.Node | Cypher.Relationship,
   186→    aggregationInputField: string,
   187→    aggregationInputValue: any
   188→): Cypher.Predicate {
   189→    const paramName = new Cypher.Param(aggregationInputValue);
   190→    const regexResult = aggregationFieldRegEx.exec(aggregationInputField)?.groups as AggregationFieldRegexGroups;
   191→    const { logicalOperator } = regexResult;
   192→    const { fieldName, aggregationOperator } = regexResult;
   193→    const fieldType = refNode.primitiveFields.find((name) => name.fieldName === fieldName)?.typeMeta.name;
   194→
   195→    if (fieldType === "String" && aggregationOperator) {
   196→        return createBaseOperation({
   197→            operator: logicalOperator || "EQ",
   198→            property: getAggregateOperation(Cypher.size(target.property(fieldName)), aggregationOperator),
   199→            param: paramName,
   200→        });
   201→    } else if (aggregationOperator) {
   202→        return createBaseOperation({
   203→            operator: logicalOperator || "EQ",
   204→            property: getAggregateOperation(target.property(fieldName), aggregationOperator),
   205→            param: paramName,
   206→        });
   207→    } else {
   208→        const innerVar = new Cypher.Variable();
   209→        const innerOperation = createBaseOperation({
   210→            operator: logicalOperator || "EQ",
   211→            property: innerVar,
   212→            param: paramName,
   213→        });
   214→
   215→        const collectedProperty =
   216→            fieldType === "String" && logicalOperator !== "EQUAL"
   217→                ? Cypher.collect(Cypher.size(target.property(fieldName)))
   218→                : Cypher.collect(target.property(fieldName));
   219→        return Cypher.any(innerVar, collectedProperty, innerOperation);
   220→    }
   221→}
   222→
   223→function getAggregateOperation(
   224→    property: Cypher.PropertyRef | Cypher.Function,
   225→    aggregationOperator: string
   226→): Cypher.Function {
   227→    switch (aggregationOperator) {
   228→        case "AVERAGE":
   229→            return Cypher.avg(property);
   230→        case "MIN":
   231→        case "SHORTEST":
   232→            return Cypher.min(property);
   233→        case "MAX":
   234→        case "LONGEST":
   235→            return Cypher.max(property);
   236→        case "SUM":
   237→            return Cypher.sum(property);
   238→        default:
   239→            throw new Error(`Invalid operator ${aggregationOperator}`);
   240→    }
   241→}
