    20→import Cypher from "@neo4j/cypher-builder";
    21→import type { Node, Relationship } from "../classes";
    22→import type { RelationField, Context, GraphQLWhereArg } from "../types";
    23→import { aggregationFieldRegEx, AggregationFieldRegexGroups, whereRegEx } from "./where/utils";
    24→import { createBaseOperation } from "./where/property-operations/create-comparison-operation";
    25→import { NODE_OR_EDGE_KEYS, LOGICAL_OPERATORS, AGGREGATION_AGGREGATE_COUNT_OPERATORS } from "../constants";
    26→
    27→type logicalOperator = "AND" | "OR";
    28→
    29→type WhereFilter = Record<string | logicalOperator, any>;
    30→
    31→export type AggregateWhereInput = {
    32→    count: number;
    33→    count_LT: number;
    34→    count_LTE: number;
    35→    count_GT: number;
    36→    count_GTE: number;
    37→    node: WhereFilter;
    38→    edge: WhereFilter;
    39→} & WhereFilter;
    40→
    41→type AggregateWhereReturn = {
    42→    returnProjections: ("*" | Cypher.ProjectionColumn)[];
    43→    predicates: Cypher.Predicate[];
    44→};
    45→
    46→export function aggregatePreComputedWhereFields(
    47→    value: GraphQLWhereArg,
    48→    relationField: RelationField,
    49→    context: Context,
    50→    matchNode: Cypher.Variable
    51→): {
    52→    predicate: Cypher.Predicate | undefined;
    53→    preComputedSubquery: Cypher.Call;
    54→} {
    55→    const refNode = context.nodes.find((x) => x.name === relationField.typeMeta.name) as Node;
    56→    const direction = relationField.direction;
    57→    const aggregationTarget = new Cypher.Node({ labels: refNode.getLabels(context) });
    58→    const cypherRelation = new Cypher.Relationship({
    59→        source: matchNode as Cypher.Node,
    60→        target: aggregationTarget,
    61→        type: relationField.type,
    62→    });
    63→    if (direction === "IN") {
    64→        cypherRelation.reverse();
    65→    }
    66→    const refRelationship = context.relationships.find(
    67→        (rel) => rel.properties === relationField.properties
    68→    ) as Relationship | undefined;
    69→    const matchQuery = new Cypher.Match(cypherRelation);
    70→    const { returnProjections, predicates } = aggregateWhere(
    71→        value as AggregateWhereInput,
    72→        refNode,
    73→        refRelationship,
    74→        aggregationTarget,
    75→        cypherRelation
    76→    );
    77→    matchQuery.return(...returnProjections);
    78→    const subquery = new Cypher.Call(matchQuery).innerWith(matchNode);
    79→    return {
    80→        predicate: Cypher.and(...predicates),
    81→        preComputedSubquery: subquery,
    82→    };
    83→}
    84→
    85→export function aggregateWhere(
    86→    aggregateWhereInput: AggregateWhereInput,
    87→    refNode: Node,
    88→    refRelationship: Relationship | undefined,
    89→    aggregationTarget: Cypher.Node,
    90→    cypherRelation: Cypher.Relationship
    91→): AggregateWhereReturn {
    92→    const returnProjections: ("*" | Cypher.ProjectionColumn)[] = [];
    93→    const predicates: Cypher.Predicate[] = [];
    94→    Object.entries(aggregateWhereInput).forEach(([key, value]) => {
    95→        if (AGGREGATION_AGGREGATE_COUNT_OPERATORS.includes(key)) {
    96→            const { returnProjection: innerReturnProjection, predicate: innerPredicate } =
    97→                createCountPredicateAndProjection(aggregationTarget, key, value);
    98→            returnProjections.push(innerReturnProjection);
    99→            predicates.push(innerPredicate);
   100→        } else if (NODE_OR_EDGE_KEYS.includes(key)) {
   101→            const target = key === "edge" ? cypherRelation : aggregationTarget;
   102→            const entityRef = key === "edge" ? refRelationship : refNode;
   103→            const { returnProjections: innerReturnProjections, predicates: innerPredicates } = aggregateEntityWhere(
   104→                value,
   105→                entityRef,
   106→                target
   107→            );
   108→            returnProjections.push(...innerReturnProjections);
   109→            predicates.push(...innerPredicates);
   110→        } else if (LOGICAL_OPERATORS.includes(key)) {
   111→            const logicalOperator = key === "AND" ? Cypher.and : Cypher.or;
   112→            const logicalPredicates: Cypher.Predicate[] = [];
   113→            value.forEach((whereInput) => {
   114→                const { returnProjections: innerReturnProjections, predicates: innerPredicates } = aggregateWhere(
   115→                    whereInput,
   116→                    refNode,
   117→                    refRelationship,
   118→                    aggregationTarget,
   119→                    cypherRelation
   120→                );
   121→                returnProjections.push(...innerReturnProjections);
   122→                logicalPredicates.push(...innerPredicates);
   123→            });
   124→            predicates.push(logicalOperator(...logicalPredicates));
   125→        }
   126→    });
   127→    return {
   128→        returnProjections,
   129→        predicates,
   130→    };
   131→}
   132→
   133→function createCountPredicateAndProjection(
   134→    aggregationTarget: Cypher.Node,
   135→    filterKey: string,
   136→    filterValue: number
   137→): {
   138→    returnProjection: "*" | Cypher.ProjectionColumn;
   139→    predicate: Cypher.Predicate;
   140→} {
   141→    const paramName = new Cypher.Param(filterValue);
   142→    const count = Cypher.count(aggregationTarget);
   143→    const operator = whereRegEx.exec(filterKey)?.groups?.operator || "EQ";
   144→    const operation = createBaseOperation({
   145→        operator,
   146→        property: count,
   147→        param: paramName,
   148→    });
   149→    const operationVar = new Cypher.Variable();
   150→    return {
   151→        returnProjection: [operation, operationVar],
   152→        predicate: Cypher.eq(operationVar, new Cypher.Literal(true)),
   153→    };
   154→}
   155→
   156→function aggregateEntityWhere(
   157→    aggregateEntityWhereInput: WhereFilter,
   158→    refNodeOrRelationship: Node | Relationship | undefined,
   159→    target: Cypher.Node | Cypher.Relationship
   160→): AggregateWhereReturn {
   161→    const returnProjections: ("*" | Cypher.ProjectionColumn)[] = [];
   162→    const predicates: Cypher.Predicate[] = [];
   163→    Object.entries(aggregateEntityWhereInput).forEach(([key, value]) => {
   164→        if (LOGICAL_OPERATORS.includes(key)) {
   165→            const logicalOperator = key === "AND" ? Cypher.and : Cypher.or;
   166→            const logicalPredicates: Cypher.Predicate[] = [];
   167→            value.forEach((whereInput) => {
   168→                const { returnProjections: innerReturnProjections, predicates: innerPredicates } = aggregateEntityWhere(
   169→                    whereInput,
   170→                    refNodeOrRelationship,
   171→                    target
   172→                );
   173→                returnProjections.push(...innerReturnProjections);
   174→                logicalPredicates.push(...innerPredicates);
   175→            });
   176→            predicates.push(logicalOperator(...logicalPredicates));
   177→        } else {
   178→            const operation = createEntityOperation(refNodeOrRelationship, target, key, value);
   179→            const operationVar = new Cypher.Variable();
   180→            returnProjections.push([operation, operationVar]);
   181→            predicates.push(Cypher.eq(operationVar, new Cypher.Literal(true)));
   182→        }
   183→    });
   184→    return {
   185→        returnProjections,
   186→        predicates,
   187→    };
   188→}
   189→
   190→function createEntityOperation(
   191→    refNodeOrRelationship: Node | Relationship | undefined,
   192→    target: Cypher.Node | Cypher.Relationship,
   193→    aggregationInputField: string,
   194→    aggregationInputValue: any
   195→): Cypher.Predicate {
   196→    const paramName = new Cypher.Param(aggregationInputValue);
   197→    const regexResult = aggregationFieldRegEx.exec(aggregationInputField)?.groups as AggregationFieldRegexGroups;
   198→    const { logicalOperator } = regexResult;
   199→    const { fieldName, aggregationOperator } = regexResult;
   200→    const fieldType = refNodeOrRelationship?.primitiveFields.find((name) => name.fieldName === fieldName)?.typeMeta.name;
   201→
   202→    if (fieldType === "String" && aggregationOperator) {
   203→        return createBaseOperation({
   204→            operator: logicalOperator || "EQ",
   205→            property: getAggregateOperation(Cypher.size(target.property(fieldName)), aggregationOperator),
   206→            param: paramName,
   207→        });
   208→    } else if (aggregationOperator) {
   209→        return createBaseOperation({
   210→            operator: logicalOperator || "EQ",
   211→            property: getAggregateOperation(target.property(fieldName), aggregationOperator),
   212→            param: paramName,
   213→        });
   214→    } else {
   215→        const innerVar = new Cypher.Variable();
   216→        const innerOperation = createBaseOperation({
   217→            operator: logicalOperator || "EQ",
   218→            property: innerVar,
   219→            param: paramName,
   220→        });
   221→
   222→        const collectedProperty =
   223→            fieldType === "String" && logicalOperator !== "EQUAL"
   224→                ? Cypher.collect(Cypher.size(target.property(fieldName)))
   225→                : Cypher.collect(target.property(fieldName));
   226→        return Cypher.any(innerVar, collectedProperty, innerOperation);
   227→    }
   228→}
   229→
   230→function getAggregateOperation(
   231→    property: Cypher.PropertyRef | Cypher.Function,
   232→    aggregationOperator: string
   233→): Cypher.Function {
   234→    switch (aggregationOperator) {
   235→        case "AVERAGE":
   236→            return Cypher.avg(property);
   237→        case "MIN":
   238→        case "SHORTEST":
   239→            return Cypher.min(property);
   240→        case "MAX":
   241→        case "LONGEST":
   242→            return Cypher.max(property);
   243→        case "SUM":
   244→            return Cypher.sum(property);
   245→        default:
   246→            throw new Error(`Invalid operator ${aggregationOperator}`);
   247→    }
   248→}
